-- ----------------------------
-- Table structure for sys_report_definition
-- ----------------------------
DROP TABLE IF EXISTS `sys_report_definition`;
CREATE TABLE `sys_report_definition`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '模板名称',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '描述',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分类',
  `data_source_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分类',
  `sql_query` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'SQL查询语句',
  `parameters_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '参数定义JSON',
  `visualization_config_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '可视化配置JSON',
  `layout_config_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '布局配置JSON',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '状态',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '报表模板定义表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_report_definition
-- ----------------------------
INSERT INTO `sys_report_definition` VALUES (1, 'user', 'user', 'user', 'target_db', 'select \r\n    id as id,\r\n    name as name,\r\n    age as age,\r\n    name as name1,\r\n    name as name2,\r\n    name as name3,\r\n    name as name4,\r\n    name as name5,\r\n    name as name6,\r\n    name as name7\r\nfrom target_user \r\nwhere 1=1 \r\n    #[and id = :id] \r\n    #[and name like :name] \r\n    #[and age > :age]', '[{\"name\":\"id\",\"type\":\"string\",\"defaultValue\":\"\",\"label\":\"id\",\"componentType\":\"input\",\"options\":\"\",\"visible\":false},{\"name\":\"name\",\"type\":\"string\",\"defaultValue\":\"\",\"label\":\"姓名\",\"componentType\":\"select\",\"options\":\"Alice:Alice,Bob:Bob\",\"visible\":true},{\"name\":\"age\",\"type\":\"number\",\"defaultValue\":\"\",\"label\":\"年龄>\",\"componentType\":\"input\",\"options\":\"\",\"visible\":true}]', '{\n  \"type\": \"table\",\n  \"columns\": [\n    {\n      \"label\": \"基础信息\",\n      \"align\": \"center\",\n      \"children\": [\n        {\n          \"label\": \"ID\",\n          \"prop\": \"id\",\n          \"width\": \"100\"\n        },\n        {\n          \"label\": \"用户名\",\n          \"prop\": \"name\"\n        },\n        {\n          \"label\": \"年龄\",\n          \"prop\": \"age\"\n        },\n        {\n          \"label\": \"用户名1\",\n          \"prop\": \"name1\"\n        },\n        {\n          \"label\": \"用户名2\",\n          \"prop\": \"name2\"\n        }\n      ]\n    },\n    {\n      \"label\": \"创建时间\",\n      \"prop\": \"created_at\",\n      \"align\": \"center\"\n    }\n  ]\n}', '{}', NULL, '2026-04-15 13:12:30', '2026-04-15 23:11:48');
INSERT INTO `sys_report_definition` VALUES (2, '用户统计', '', '用户', 'target_db', 'select \r\n    name as name,\r\n    max(age) age,\r\n    count(1) num\r\nfrom target_user \r\nwhere 1=1\r\n#[name like :name]\r\ngroup by name', '[{\"name\":\"name\",\"type\":\"string\",\"defaultValue\":\"\",\"label\":\"姓名\",\"componentType\":\"input\",\"options\":\"\",\"visible\":true}]', '{\n  \"widgets\": [\n    {\n      \"id\": \"chart1\",\n      \"type\": \"chart\",\n      \"title\": \"柱状图\",\n      \"chartConfig\": {\n        \"chartType\": \"bar\",\n        \"xAxis\": \"name\",\n        \"yAxis\": [\"age\",\"num\"],\n        \"seriesNames\": [\"年龄\",\"数量\"]\n      }\n    }, {\n      \"id\": \"chart2\",\n      \"type\": \"chart\",\n      \"title\": \"折线图\",\n      \"chartConfig\": {\n        \"chartType\": \"line\",\n        \"xAxis\": \"name\",\n        \"yAxis\": [\"age\",\"num\"],\n        \"seriesNames\": [\"年龄\",\"数量\"]\n      }\n    },\n    {\n      \"id\": \"table1\",\n      \"type\": \"table\",\n      \"title\": \"明细数据\",\n      \"tableConfig\": { \"columns\": [\n          {\n            \"label\": \"基础信息\",\n            \"children\": [\n              {\n                \"label\": \"姓名\",\n                \"prop\": \"name\"\n              },\n              {\n                \"label\": \"年龄\",\n                \"prop\": \"age\"\n              },\n              {\n                \"label\": \"数量\",\n                \"prop\": \"num\"\n              }\n            ]\n          }\n        ] }\n    }\n  ]\n}', '{\r\n  \"layout\": \"grid\",\r\n  \"items\": [\r\n    {\r\n      \"widgetId\": \"chart1\",\r\n      \"span\": 6,\r\n      \"height\": 300\r\n    },\r\n    {\r\n      \"widgetId\": \"chart2\",\r\n      \"span\": 6,\r\n      \"height\": 300\r\n    },\r\n    {\r\n      \"widgetId\": \"table1\",\r\n      \"span\": 12,\r\n      \"height\": 500\r\n    }\r\n  ]\r\n}', NULL, '2026-04-15 22:13:49', '2026-04-15 23:30:23');

-- ----------------------------
-- Table structure for sys_report_instance
-- ----------------------------
DROP TABLE IF EXISTS `sys_report_instance`;
CREATE TABLE `sys_report_instance`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `definition_id` bigint NOT NULL COMMENT '模板ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '实例名称',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '描述',
  `data_source_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '数据源编码',
  `actual_parameters_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '实际参数JSON',
  `publish_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'DRAFT' COMMENT '发布状态(DRAFT,PUBLISHED,OFFLINE)',
  `access_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '访问URL',
  `visibility` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '可见性',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '报表实例表' ROW_FORMAT = Dynamic;

