ity_0rc8cli\" targetRef=\"Activity_0coshjn\" />\n    <sequenceFlow id=\"Flow_0t8yylh\" sourceRef=\"Gateway_0doo7tw\" targetRef=\"Activity_0rc8cli\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${outcome== \'REJECT\'}</conditionExpression>\n    </sequenceFlow>\n    <endEvent id=\"Event_1yieqph\">\n      <incoming>Flow_0f0mviv</incoming>\n    </endEvent>\n    <sequenceFlow id=\"Flow_0f0mviv\" sourceRef=\"Gateway_0doo7tw\" targetRef=\"Event_1yieqph\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${outcome== \'APPROVE\'}</conditionExpression>\n    </sequenceFlow>\n    <userTask id=\"Activity_0coshjn\" name=\"一级审批\" flowable:formKey=\"Approve:Level1\" flowable:candidateGroups=\"\" flowable:assignee=\"2\">\n      <documentation>一级审批</documentation>\n      <incoming>Flow_0wz9lm7</incoming>\n      <incoming>Flow_1q40gxc</incoming>\n      <outgoing>Flow_03t0pxd</outgoing>\n    </userTask>\n    <userTask id=\"Activity_19j66xd\" name=\"二级审批\" flowable:formKey=\"Approve:Level2\" flowable:candidateUsers=\"1,2\">\n      <incoming>Flow_1ihuixz</incoming>\n      <outgoing>Flow_13nqowp</outgoing>\n    </userTask>\n    <userTask id=\"Activity_0rc8cli\" name=\"返回填写\">\n      <incoming>Flow_0mjhzuw</incoming>\n      <incoming>Flow_0t8yylh</incoming>\n      <outgoing>Flow_1q40gxc</outgoing>\n    </userTask>\n  </process>\n  <bpmndi:BPMNDiagram id=\"BPMNDiagram_flow\">\n    <bpmndi:BPMNPlane id=\"BPMNPlane_flow\" bpmnElement=\"process_fyjyprgp\">\n      <bpmndi:BPMNEdge id=\"Flow_0f0mviv_di\" bpmnElement=\"Flow_0f0mviv\">\n        <di:waypoint x=\"735\" y=\"210\" />\n        <di:waypoint x=\"809\" y=\"210\" />\n        <di:waypoint x=\"809\" y=\"220\" />\n        <di:waypoint x=\"902\" y=\"220\" />\n      </bpmndi:BPMNEdge>\n      <bpmndi:BPMNEdge id=\"Flow_0t8yylh_di\" bpmnElement=\"Flow_0t8yylh\">\n        <di:waypoint x=\"710\" y=\"235\" />\n        <di:waypoint x=\"710\" y=\"460\" />\n        <di:waypoint x=\"400\" y=\"460\" />\n      </bpmndi:BPMNEdge>\n